#include "ws2812b_matrix.h"
#define MAX_LEDS 256
#define DATA_PIN 16
static CRGB leds[MAX_LEDS];
static uint16_t _numLeds=0;
void ws2812b_setup(uint16_t n){_numLeds=min((uint16_t)MAX_LEDS,n);FastLED.addLeds<WS2812B,DATA_PIN,GRB>(leds,_numLeds);FastLED.setBrightness(50);FastLED.clear();FastLED.show();Serial.printf("[ws2812b] OK %d LEDs\n",_numLeds);}
void ws2812b_set(uint16_t i,uint8_t r,uint8_t g,uint8_t b){if(i<_numLeds)leds[i]=CRGB(r,g,b);}
void ws2812b_fill(uint8_t r,uint8_t g,uint8_t b){fill_solid(leds,_numLeds,CRGB(r,g,b));}
void ws2812b_show(){FastLED.show();}
void ws2812b_clear(){FastLED.clear();FastLED.show();}
void ws2812b_rainbow(){fill_rainbow(leds,_numLeds,millis()/10,7);FastLED.show();}
